/*
 * experiment.c — BitDogLab Automated NN Architecture Search
 *
 * Imports a GENANN_NN_DATASET header (data.h, generated by csv2header.py)
 * and trains multiple neural-network architectures sequentially, streaming
 * training metrics over a dedicated UART to metric_listener.py.
 *
 * No flash saving — the last fully-trained model is kept in RAM and used
 * directly when switching to inference mode.
 *
 * ── Button map ──────────────────────────────────────────────────────────────
 *  B               toggle Training ↔ Inference
 *  Joystick SW     (training) skip current architecture
 *
 * ── Inference mode ──────────────────────────────────────────────────────────
 *  Identical to main.c: joystick position → LED matrix (blue, threshold-gated).
 *  If no model has been trained yet the matrix stays dark.
 *
 * ── UART metric protocol (metric_listener.py) ───────────────────────────────
 *  M:BOOT
 *  M:START,<ai>,<n>,<hl>,<h>,<lr>,<passes>,<train_len>,<val_len>
 *  M:EP,<ai>,<ep>,<tLoss>,<vLoss>,<tAcc>,<vAcc>
 *  M:DONE,<ai>,<n>,<tLoss>,<vLoss>,<tAcc>,<vAcc>,<passes>
 *  M:ALL_DONE
 */

#include <stdio.h>
#include <stdarg.h>
#include <string.h>
#include <math.h>

#include "pico/stdlib.h"
#include "pico/rand.h"
#include "hardware/uart.h"
#include "hardware/gpio.h"

#define BOARD_PWM_HELPERS
#define BOARD_BUTTON_HELPERS
#define BOARD_ADC_HELPERS
#include "bitdoglab.h"

#define BDLED_IMPLEMENTATION
#include "bdl_led_matrix.h"

#define SSD1306_IMPLEMENTATION
#include "stb_ssd1306.h"

#include "rtos.h"
#include "gennan.h"
#include "data.h"   /* GENANN_NN_DATASET — generated by csv2header.py */

/* ── RNG (required by genann) ─────────────────────────────────────────────── */
int internal_rand(void)   { return (int)(get_rand_32() >> 1); }
int INTERNAL_RAND_MAX     = 0x7FFFFFFF;

/* ═══════════════════════════════════════════════════════════════════════════
 * Metric UART  (uart1 / pin 4 — separate from USB stdio)
 * ═══════════════════════════════════════════════════════════════════════════ */
#define METRIC_UART         uart1
#define METRIC_UART_TX_PIN  4
#define METRIC_UART_BAUD    115200

static void metric_uart_init(void) {
    uart_init(METRIC_UART, METRIC_UART_BAUD);
    gpio_set_function(METRIC_UART_TX_PIN, GPIO_FUNC_UART);
}

static void metric_send(const char *fmt, ...) {
    char buf[160];
    va_list ap;
    va_start(ap, fmt);
    vsnprintf(buf, sizeof(buf), fmt, ap);
    va_end(ap);
    
    // Print with prefix so --stdio-only mode can filter them
    printf("%s\r\n", buf);           // ← important: M: prefix + \r\n
}


/* ═══════════════════════════════════════════════════════════════════════════
 * Architecture list
 * ═══════════════════════════════════════════════════════════════════════════ */
typedef double (*ActFn)(const genann *, double);

typedef struct {
    const char *name;
    int         hidden_layers;
    int         hidden;
    ActFn       act_hidden;
    ActFn       act_output;
    double      lr;
} NNArch;

static const NNArch ARCH_LIST[] = {
    { "sig_1x8",   1,  8, genann_act_sigmoid, genann_act_sigmoid, 0.10 },
    { "sig_2x16",  2, 16, genann_act_sigmoid, genann_act_sigmoid, 0.05 },
    { "relu_2x16", 2, 16, genann_act_relu,    genann_act_sigmoid, 0.05 },
    { "relu_2x32", 2, 32, genann_act_relu,    genann_act_sigmoid, 0.03 },
    { "relu_3x32", 3, 32, genann_act_relu,    genann_act_sigmoid, 0.01 },
    { "sig_2x32",  2, 32, genann_act_sigmoid, genann_act_sigmoid, 0.03 },
};
#define ARCH_COUNT   ((int)(sizeof(ARCH_LIST) / sizeof(ARCH_LIST[0])))
#define TRAIN_PASSES 30

/* ═══════════════════════════════════════════════════════════════════════════
 * Display types
 * ═══════════════════════════════════════════════════════════════════════════ */
#define MATRIX_ROWS   5
#define MATRIX_COLS   5
#define MATRIX_CELLS  (MATRIX_ROWS * MATRIX_COLS)
#define INFER_THRESH  0.2
#define LCD_LINE_H    12
#define LCD_BUF_SZ    64

typedef enum { EXP_MODE_TRAINING, EXP_MODE_INFERENCE } ExpMode;

typedef struct {
    ExpMode  mode;
    char     arch_name[16];
    int      arch_idx;
    int      pass;
    float    train_loss, val_loss;
    float    train_acc,  val_acc;
    bool     has_model;  /* true once at least one arch has finished */
} LCDPayload;

static QueueHandle_t xLCDQ;
static QueueHandle_t xBtnQ;
static void push_lcd(const LCDPayload *p) { xQueueOverwrite(xLCDQ, p); }

/* ═══════════════════════════════════════════════════════════════════════════
 * Training helpers
 * ═══════════════════════════════════════════════════════════════════════════ */
static float compute_mse(const double *out, const double *tgt, int n) {
    float s = 0.0f;
    for (int i = 0; i < n; i++) { float d = (float)(out[i] - tgt[i]); s += d*d; }
    return s / (float)n;
}

static float compute_acc(const double *out, const double *tgt, int n) {
    int ok = 0;
    for (int i = 0; i < n; i++)
        if (((out[i] >= INFER_THRESH) ? 1 : 0) == ((tgt[i] >= 0.5) ? 1 : 0)) ok++;
    return (float)ok / (float)n;
}

static void eval_split(genann *ann,
                        const double (*ins)[2],
                        const double (*outs)[MATRIX_CELLS],
                        int count,
                        float *mse_out, float *acc_out) {
    float ms = 0.0f, as = 0.0f;
    for (int i = 0; i < count; i++) {
        const double *pred = genann_run(ann, ins[i]);
        ms += compute_mse(pred, outs[i], MATRIX_CELLS);
        as += compute_acc(pred, outs[i], MATRIX_CELLS);
        if ((i & 31) == 31) vTaskDelay(1); /* keep Core 1 tasks alive */
    }
    *mse_out = count > 0 ? ms / count : 1.0f;
    *acc_out = count > 0 ? as / count : 0.0f;
}

static void shuffle_indices(int *idx, int n, uint32_t seed) {
    uint32_t s = seed ^ (uint32_t)n ^ 0xDEADBEEFu;
    for (int i = n - 1; i > 0; i--) {
        s ^= s << 13; s ^= s >> 17; s ^= s << 5;
        int j = (int)(s % (uint32_t)(i + 1));
        int t = idx[i]; idx[i] = idx[j]; idx[j] = t;
    }
}

static void xavier_init(genann *ann) {
    double scale = sqrt(2.0 / (ann->inputs + ann->hidden));
    for (int i = 0; i < ann->total_weights; i++) {
        double u1 = (get_rand_32() + 1.0) / 0x100000000ULL;
        double u2 = (get_rand_32() + 1.0) / 0x100000000ULL;
        ann->weight[i] = sqrt(-2.0 * log(u1)) * cos(2.0 * M_PI * u2) * scale;
    }
}

/* ═══════════════════════════════════════════════════════════════════════════
 * LED matrix helpers
 * ═══════════════════════════════════════════════════════════════════════════ */
static LedMatrix g_matrix = {0};

/* Inference display — identical to main.c matrix_show_inference */
static void matrix_show_inference(const double *out) {
    if (xSemaphoreTake(xMatrixMutex, pdMS_TO_TICKS(100)) != pdPASS) return;
    bdl_matrixClear(&g_matrix);
    for (int row = 0; row < MATRIX_ROWS; row++) {
        for (int col = 0; col < MATRIX_COLS; col++) {
            double v = out[row * MATRIX_COLS + col];
            if (v >= INFER_THRESH) {
                float w = 0.1f * (float)((v - INFER_THRESH) / (1.0 - INFER_THRESH));
                bdl_matrixSetPixel(&g_matrix, row, col, 0, 0, 255, w);
            }
        }
    }
    xSemaphoreGive(xMatrixMutex);
}

/* Training progress: one row per arch, fills left→right */
static void matrix_train_progress(int arch_idx, int ep) {
    if (xSemaphoreTake(xMatrixMutex, pdMS_TO_TICKS(50)) != pdPASS) return;
    bdl_matrixClear(&g_matrix);
    int row = arch_idx % MATRIX_ROWS;
    int lit = (int)((float)(ep + 1) / TRAIN_PASSES * MATRIX_COLS);
    for (int c = 0; c < lit && c < MATRIX_COLS; c++)
        bdl_matrixSetPixel(&g_matrix, row, c, 0, 200, 80, 0.08f);
    xSemaphoreGive(xMatrixMutex);
}

/* ═══════════════════════════════════════════════════════════════════════════
 * Global flags
 * ═══════════════════════════════════════════════════════════════════════════ */
static volatile ExpMode g_mode      = EXP_MODE_TRAINING;
static volatile bool    g_skip_arch = false;
static volatile bool    g_retrain_requested = true;

/* ═══════════════════════════════════════════════════════════════════════════
 * ISR
 * ═══════════════════════════════════════════════════════════════════════════ */
static volatile uint32_t g_last_isr_ms = 0;

void ISR_HandleButtons(uint gpio, uint32_t events) {
    (void)events;
    uint32_t now = to_ms_since_boot(get_absolute_time());
    BaseType_t hp = pdFALSE;
    if (now - g_last_isr_ms > 100 &&
        (gpio == BOARD_BUTTON_A || gpio == BOARD_BUTTON_B || gpio == BOARD_BUTTON_JOYSTICK)) {
        xQueueOverwriteFromISR(xBtnQ, &gpio, &hp);
        g_last_isr_ms = now;
    }
    portYIELD_FROM_ISR(hp);
}

/* ═══════════════════════════════════════════════════════════════════════════
 * Tasks
 * ═══════════════════════════════════════════════════════════════════════════ */

void deviceAliveTask(void *p) {
    (void)p;
    setup_rgb_led_with_bright();
    bool st = false;
    const Color white = {255, 255, 255};
    for (;;) {
        rgb_led_put_with_bright(white, st ? 3.0f : 0.0f);
        st = !st;
        vTaskDelay(pdMS_TO_TICKS(500));
    }
}

void buttonsTask(void *p) {
    (void)p;
    uint32_t btn;
    for (;;) {
        if (xQueueReceive(xBtnQ, &btn, portMAX_DELAY) != pdPASS) continue;
        if (gpio_get((uint)btn) != BOARD_BUTTON_ON) continue;

        if (btn == BOARD_BUTTON_B) {
            g_mode = (g_mode == EXP_MODE_TRAINING) ? EXP_MODE_INFERENCE : EXP_MODE_TRAINING;
            printf("[BTN] Mode -> %s\n",
                   g_mode == EXP_MODE_TRAINING ? "TRAINING" : "INFERENCE");
        } else if (btn == BOARD_BUTTON_JOYSTICK && g_mode == EXP_MODE_TRAINING) {
            g_skip_arch = true;
            printf("[BTN] Skip requested\n");
        }
    }
}

void readJoystickTask(void *p) {
    (void)p;
    setup_joystick();
    const uint16_t DZ = 150;
    float alpha = 0.4f;
    JoystickState s = {0};
    for (;;) {
        s = read_joystick();
        s = apply_low_pass_filter(s, &alpha);
        s.x = apply_joystick_deadzone(s.x, DZ) == 0 ? 2048 : s.x;
        s.y = apply_joystick_deadzone(s.y, DZ) == 0 ? 2048 : s.y;
        xQueueOverwrite(xJoystickQueue, &s);
        vTaskDelay(pdMS_TO_TICKS(20));
    }
}

void matrixUpdateTask(void *p) {
    (void)p;
    bdl_matrixInit(&g_matrix, LED_PIN, MATRIX_ROWS, MATRIX_COLS);
    xSemaphoreGive(xMatrixMutex);
    for (;;) {
        if (xSemaphoreTake(xMatrixMutex, portMAX_DELAY) == pdPASS) {
            bdl_matrixWrite(&g_matrix);
            xSemaphoreGive(xMatrixMutex);
        }
        vTaskDelay(pdMS_TO_TICKS(33));
    }
}

void lcdUpdateTask(void *p) {
    (void)p;
    ssd1306_i2c_setup();
    clear_screen();
    LCDPayload info = {0};
    static char buf[LCD_BUF_SZ];
    uint8_t y;
    for (;;) {
        xQueueReceive(xLCDQ, &info, pdMS_TO_TICKS(200));
        ssd1306_clear_rect_area(0, 0, ssd1306_width, ssd1306_height);
        y = 2;

        if (info.mode == EXP_MODE_TRAINING) {
            snprintf(buf, sizeof(buf), "[TRAIN] %d/%d", info.arch_idx + 1, ARCH_COUNT);
            ssd1306_draw_string((uint8_t *)ssd, 0, y, buf); y += LCD_LINE_H;
            ssd1306_draw_string((uint8_t *)ssd, 0, y, (char *)info.arch_name); y += LCD_LINE_H;
            snprintf(buf, sizeof(buf), "Ep %d/%d", info.pass + 1, TRAIN_PASSES);
            ssd1306_draw_string((uint8_t *)ssd, 0, y, buf); y += LCD_LINE_H;
            snprintf(buf, sizeof(buf), "tL%.4f vL%.4f",
                     (double)info.train_loss, (double)info.val_loss);
            ssd1306_draw_string((uint8_t *)ssd, 0, y, buf);
        } else {
            ssd1306_draw_string((uint8_t *)ssd, 0, y,
                info.has_model ? "[INFER]" : "[INFER] No model"); y += LCD_LINE_H;
            if (info.has_model) {
                ssd1306_draw_string((uint8_t *)ssd, 0, y, (char *)info.arch_name); y += LCD_LINE_H;
                snprintf(buf, sizeof(buf), "vL%.4f vA%.0f%%",
                         (double)info.val_loss, (double)(info.val_acc * 100.0f));
                ssd1306_draw_string((uint8_t *)ssd, 0, y, buf); y += LCD_LINE_H;
            }
            ssd1306_draw_string((uint8_t *)ssd, 0, y, "Joystick->LEDs");
        }
        render_on_display((uint8_t *)ssd, &frame_area);
        vTaskDelay(pdMS_TO_TICKS(200));
    }
}

/* ═══════════════════════════════════════════════════════════════════════════
 * neuralNetTask
 * ═══════════════════════════════════════════════════════════════════════════ */
void neuralNetTask(void *p) {
    (void)p;
    vTaskDelay(pdMS_TO_TICKS(600));

    static int last_completed_arch = -1;
    static int train_idx[DATASET_TRAIN_LEN];
    for (int i = 0; i < DATASET_TRAIN_LEN; i++) train_idx[i] = i;
    
    /* Last fully-trained model — lives in RAM, used directly for inference */
    genann *inf_ann           = NULL;
    char    inf_arch_name[16] = {0};
    float   inf_val_loss      = 1.0f;
    float   inf_val_acc       = 0.0f;

    LCDPayload lcd = {0};

    metric_send("M:BOOT");

    lcd.mode = EXP_MODE_TRAINING;
    strncpy(lcd.arch_name, "Starting...", 15);
    push_lcd(&lcd);

    for (;;) {

        /* ══ INFERENCE MODE — identical to main.c ═══════════════════════════ */
        if (g_mode == EXP_MODE_INFERENCE) {
            lcd.mode      = EXP_MODE_INFERENCE;
            lcd.has_model = (inf_ann != NULL);
            lcd.val_loss  = inf_val_loss;
            lcd.val_acc   = inf_val_acc;
            strncpy(lcd.arch_name, inf_arch_name, 15);
            push_lcd(&lcd);

            if (inf_ann) {
                JoystickState joy = {0};
                if (xQueuePeek(xJoystickQueue, &joy, pdMS_TO_TICKS(100)) == pdPASS) {
                    double nn_in[2] = {
                        (double)map_joystick_value(joy.x, -1.0f, 1.0f),
                        (double)map_joystick_value(joy.y, -1.0f, 1.0f),
                    };
                    matrix_show_inference(genann_run(inf_ann, nn_in));
                }
            }
            vTaskDelay(pdMS_TO_TICKS(50));
            continue;
        }

        /* ══ TRAINING MODE ══════════════════════════════════════════════════ */
        for (int ai = 0; ai < ARCH_COUNT; ai++) {
            if (g_mode != EXP_MODE_TRAINING) break;

            // ── Skip already trained architectures ───────────────────────
            if (ai <= last_completed_arch) {
                printf("[TRAIN] Skipping already trained: %s\n", ARCH_LIST[ai].name);
                continue;
            }

            const NNArch *arch = &ARCH_LIST[ai];
            printf("[TRAIN] ── Arch %d/%d: %s  (hl=%d h=%d lr=%.4f) ──\n",
                   ai + 1, ARCH_COUNT, arch->name,
                   arch->hidden_layers, arch->hidden, arch->lr);

            metric_send("M:START,%d,%s,%d,%d,%.5f,%d,%d,%d",
                        ai, arch->name, arch->hidden_layers, arch->hidden,
                        arch->lr, TRAIN_PASSES, DATASET_TRAIN_LEN, DATASET_VAL_LEN);

            genann *ann = genann_init(2, arch->hidden_layers, arch->hidden, MATRIX_CELLS);
            if (!ann) { printf("[TRAIN] genann_init failed\n"); continue; }
            ann->activation_hidden = arch->act_hidden;
            ann->activation_output = arch->act_output;
            xavier_init(ann);

            g_skip_arch = false;

            for (int ep = 0; ep < TRAIN_PASSES; ep++) {
                if (g_mode != EXP_MODE_TRAINING || g_skip_arch) break;

                shuffle_indices(train_idx, DATASET_TRAIN_LEN,
                                (uint32_t)(ai * 0x1000u + ep * 0x9E3779B9u));

                for (int si = 0; si < DATASET_TRAIN_LEN; si++) {
                    genann_train(ann,
                                 dataset_input [train_idx[si]],
                                 dataset_output[train_idx[si]],
                                 arch->lr);
                    if ((si & 31) == 31) vTaskDelay(1);
                }

                float tl, ta, vl, va;
                eval_split(ann, dataset_input, dataset_output,
                           DATASET_TRAIN_LEN, &tl, &ta);
                eval_split(ann,
                           dataset_input  + DATASET_VAL_OFFSET,
                           dataset_output + DATASET_VAL_OFFSET,
                           DATASET_VAL_LEN, &vl, &va);

                metric_send("M:EP,%d,%d,%.6f,%.6f,%.4f,%.4f",
                            ai, ep, (double)tl, (double)vl,
                            (double)ta, (double)va);

                lcd.mode       = EXP_MODE_TRAINING;
                lcd.arch_idx   = ai;
                lcd.pass       = ep;
                lcd.train_loss = tl; lcd.val_loss = vl;
                lcd.train_acc  = ta; lcd.val_acc  = va;
                strncpy(lcd.arch_name, arch->name, 15);
                push_lcd(&lcd);

                matrix_train_progress(ai, ep);

                printf("[TRAIN] %s  ep=%d  tL=%.4f vL=%.4f  tA=%.0f%% vA=%.0f%%\n",
                       arch->name, ep,
                       (double)tl, (double)vl,
                       (double)(ta * 100.0f), (double)(va * 100.0f));

                vTaskDelay(pdMS_TO_TICKS(2));
            }

            /* Final metrics */
            float tl, ta, vl, va;
            eval_split(ann, dataset_input, dataset_output, DATASET_TRAIN_LEN, &tl, &ta);
            eval_split(ann,
                       dataset_input  + DATASET_VAL_OFFSET,
                       dataset_output + DATASET_VAL_OFFSET,
                       DATASET_VAL_LEN, &vl, &va);

            metric_send("M:DONE,%d,%s,%.6f,%.6f,%.4f,%.4f,%d",
                        ai, arch->name,
                        (double)tl, (double)vl,
                        (double)ta, (double)va, TRAIN_PASSES);

            // ── Only update last_completed_arch when we fully finish an arch ──
            if (g_mode == EXP_MODE_TRAINING && !g_skip_arch) {
                last_completed_arch = ai;               // ← key line

                if (inf_ann) genann_free(inf_ann);
                inf_ann = ann;
                ann = NULL;
                strncpy(inf_arch_name, arch->name, sizeof(inf_arch_name)-1);
                inf_val_loss = vl;
                inf_val_acc  = va;
                printf("[INF] Best so far updated to %s (ai=%d)\n", inf_arch_name, ai);
            }

            if (ann) { genann_free(ann); ann = NULL; }
            vTaskDelay(pdMS_TO_TICKS(200));
        }

        if (g_mode == EXP_MODE_TRAINING) {
            metric_send("M:ALL_DONE");
            printf("[TRAIN] All done. BTN-B → inference | Joystick SW → retrain\n");
            while (g_mode == EXP_MODE_TRAINING && !g_skip_arch)
                vTaskDelay(pdMS_TO_TICKS(500));
            g_skip_arch = false;
        }
    }
}

/* ═══════════════════════════════════════════════════════════════════════════
 * main
 * ═══════════════════════════════════════════════════════════════════════════ */
int main(void) {
    stdio_init_all();
    sleep_ms(2000);
    printf("[SYS] experiment.c — NN Architecture Search v1\n");

    metric_uart_init();

    init_buttons(&ISR_HandleButtons);
    init_rtos_handlers();

    xLCDQ = xQueueCreate(1, sizeof(LCDPayload));
    xBtnQ = xQueueCreate(1, sizeof(uint32_t));

    /* Core 0 */
    xTaskCreateAffinitySet(deviceAliveTask, "Alive",    512,  NULL,  1, RP2040_CORE_0, NULL);
    xTaskCreateAffinitySet(buttonsTask,     "Buttons",  512,  NULL,  6, RP2040_CORE_0, NULL);
    xTaskCreateAffinitySet(neuralNetTask,   "NeuralNet",8192, NULL,  5, RP2040_CORE_0, NULL);

    /* Core 1 */
    xTaskCreateAffinitySet(readJoystickTask, "Joystick", 1024, NULL, 10, RP2040_CORE_1, NULL);
    xTaskCreateAffinitySet(matrixUpdateTask, "Matrix",   1024, NULL, 10, RP2040_CORE_1, NULL);
    xTaskCreateAffinitySet(lcdUpdateTask,    "LCD",      2048, NULL,  7, RP2040_CORE_1, NULL);

    vTaskStartScheduler();
    while (true) tight_loop_contents();
}